  "strict": true,
  "parameters": {
    "type": "object",
    "additionalProperties": false,
    "required": ["classification"],
    "properties": {
      "classification": {
        "type": "string",
        "enum": [
          "緊急",
          "通常",
          "NO_RESULT"
        ]
      }
    }
